 47	
 48	static K_FIFO_DEFINE(cmds_queue);
 49	static K_FIFO_DEFINE(avail_queue);
 50	
 51	static struct btp_buf *delayed_cmd;
 52	
 53	static struct {
 54		const struct btp_handler *handlers;
 55		size_t num;
 56	} service_handler[BTP_SERVICE_ID_MAX + 1];
 57	
 58	static struct net_buf_simple *rsp_buf = NET_BUF_SIMPLE(BTP_MTU);
 59	static K_MUTEX_DEFINE(rsp_buf_mutex);
 60	
 61	static void tester_send_with_index(uint8_t service, uint8_t opcode, uint8_t index,
 62					   const uint8_t *data, size_t len);
 63	static void tester_rsp_with_index(uint8_t service, uint8_t opcode, uint8_t index,
 64					  uint8_t status);
 65	
 66	void tester_register_command_handlers(uint8_t service,
 67					      const struct btp_handler *handlers,
 68					      size_t num)
 69	{
 70		__ASSERT_NO_MSG(service <= BTP_SERVICE_ID_MAX);
 71		__ASSERT_NO_MSG(service_handler[service].handlers == NULL);
 72	
 73		service_handler[service].handlers = handlers;
 74		service_handler[service].num = num;
 75	}
 76	
 77	static const struct btp_handler *find_btp_handler(uint8_t service, uint8_t opcode)
 78	{
 79		if ((service > BTP_SERVICE_ID_MAX) ||
 80		    (service_handler[service].handlers == NULL)) {
 81			return NULL;
 82		}
 83	
 84		for (uint8_t i = 0; i < service_handler[service].num; i++) {
 85			if (service_handler[service].handlers[i].opcode == opcode) {
 86				return &service_handler[service].handlers[i];
 87			}
 88		}
 89	
 90		return NULL;
 91	}
 92	
 93	static void cmd_handler(void *p1, void *p2, void *p3)
 94	{
 95		while (1) {
 96			const struct btp_handler *btp;
 97			struct btp_buf *cmd;
 98			struct btp_hdr *hdr;
 99			uint8_t status;
100			uint16_t rsp_len = 0;
101	
102			cmd = k_fifo_get(&cmds_queue, K_FOREVER);
103			hdr = (struct btp_hdr *)cmd->data;
104	
105			LOG_DBG("cmd service 0x%02x opcode 0x%02x index 0x%02x",
106				hdr->service, hdr->opcode, hdr->index);
107	
108			btp = find_btp_handler(hdr->service, hdr->opcode);
109			if (btp) {
110				uint16_t len = sys_le16_to_cpu(hdr->len);
111	
112				if (len > BTP_DATA_MAX_SIZE) {
113					status = BTP_STATUS_FAILED;
114					LOG_ERR("Data len exceeds BTP MTU %u > %u", len, BTP_DATA_MAX_SIZE);
115				} else if (btp->index != hdr->index) {
116					status = BTP_STATUS_FAILED;
117					LOG_ERR("Index mismatch %u != %u", btp->index, hdr->index);
118				} else if ((btp->expect_len >= 0) && (btp->expect_len != len)) {
119					status = BTP_STATUS_FAILED;
120					LOG_ERR("len mismatch %u != %u", btp->expect_len, len);
121				} else {
122					status = btp->func(hdr->data, len,
123							   cmd->rsp, &rsp_len);
124					LOG_DBG("Command returns status %u", status);
125				}
126	
127				/* This means that caller likely overwrote rsp buffer */
128				__ASSERT_NO_MSG(rsp_len <= BTP_DATA_MAX_SIZE);
129			} else {
130				status = BTP_STATUS_UNKNOWN_CMD;
131			}
132			/* Allow to delay only 1 command. This is for convenience only
133			 * of using cmd data without need of copying those in async
134			 * functions. Should be not needed eventually.
135			 */
136			if (status == BTP_STATUS_DELAY_REPLY) {
137				__ASSERT_NO_MSG(delayed_cmd == NULL);
138				delayed_cmd = cmd;
139				continue;
140			}
141	
142			if ((status == BTP_STATUS_SUCCESS) && rsp_len > 0) {
143				tester_send_with_index(hdr->service, hdr->opcode,
144						       hdr->index, cmd->rsp, rsp_len);
145			} else {
146				tester_rsp_with_index(hdr->service, hdr->opcode,
147						      hdr->index, status);
148			}
149	
150			(void)memset(cmd, 0, sizeof(*cmd));
151			k_fifo_put(&avail_queue, cmd);
152		}
153	}
154	
155	static uint8_t *recv_cb(uint8_t *buf, size_t *off)
156	{
157		struct btp_hdr *cmd = (void *) buf;
158		struct btp_buf *new_buf;
159		uint16_t len;
160	
161		if (*off < sizeof(*cmd)) {
162			return buf;
163		}
164	
165		len = sys_le16_to_cpu(cmd->len);
166		if (len > BTP_MTU - sizeof(*cmd)) {
167			LOG_ERR("BT tester: invalid packet length");
168			*off = 0;
169			return buf;
170		}
171	
172		if (*off < sizeof(*cmd) + len) {
173			return buf;
174		}
175	
176		new_buf =  k_fifo_get(&avail_queue, K_NO_WAIT);
177		if (!new_buf) {
178			LOG_ERR("BT tester: RX overflow");
179			*off = 0;
180			return buf;
181		}
182	
183		k_fifo_put(&cmds_queue, CONTAINER_OF(buf, struct btp_buf, data[0]));
184	
185		*off = 0;
186		return new_buf->data;
187	}
